package com.socialblog.comment.application;import com.fasterxml.jackson.databind.ObjectMapper;import com.socialblog.comment.domain.*;import com.socialblog.comment.repository.*;import org.junit.jupiter.api.Test;import java.util.*;import static org.assertj.core.api.Assertions.assertThat;import static org.mockito.Mockito.*;
class ArticleEventConsumerTest{@Test void appliesOnceAndDeduplicates()throws Exception{ArticleProjectionRepository articles=mock(ArticleProjectionRepository.class);ProcessedEventRepository processed=mock(ProcessedEventRepository.class);UUID event=UUID.randomUUID(),article=UUID.randomUUID();when(processed.existsById(event)).thenReturn(false,true);when(articles.findById(article)).thenReturn(Optional.empty());ArticleEventConsumer c=new ArticleEventConsumer(new ObjectMapper(),articles,processed);String raw="{\"eventId\":\""+event+"\",\"eventType\":\"ArticlePublished\",\"payload\":{\"articleId\":\""+article+"\"}}";c.consume(raw);c.consume(raw);verify(articles,times(1)).save(argThat(ArticleProjection::isActive));verify(processed,times(1)).save(any(ProcessedEvent.class));}}
